import * as fs from 'fs/promises';
import * as path from 'path';

export interface ChronosSpec {
  taskNumber: number;
  identity: string;
  gap: string;
  deliverables: string[];
  criteria: string[];
}

export interface TaskOutcome {
  success: boolean;
  filesCreated: string[];
  validation: {
    allCriteriaMet: boolean;
    details: Array<{
      criterion: string;
      met: boolean;
      evidence: string;
    }>;
  };
}

export interface AnalyticResult {
  taskNumber: number;
  identity: string;
  initialInquiry: string;
  socraticFindings: {
    expectedSuccess: boolean;
    actualSuccess: boolean;
    meetsSpec: boolean;
  };
